public class Solution { public int[] TwoSum(int[] nums, int target) { Dictionary<int, int> dict = new Dictionary<int, int>(); for (int i = 0; i < nums.Length; i++) { int differece = target - nums[i]; if (!dict.ContainsKey(differece)) { dict.Add(nums[i], i); } else { return new int[] { dict[differece], i }; } } throw new InvalidOperationException("No two sum solution found."); } }